export default function App() {
  const [leaders, setLeaders] = useState([]);
  const [history, setHistory] = useState([]);
  const [stats, setStats] = useState({});

  useEffect(() => {
    (async () => {
      try {
        const [lb, hist, cats] = await Promise.all([
          axios.get(`${API}/leaderboard`),
          axios.get(`${API}/games?limit=12`),
          axios.get(`${API}/categories`),
        ]);
        setLeaders(lb.data || []);
        setHistory(hist.data || []);
        const players = new Set();
        (hist.data || []).forEach((g) => g.players.forEach((p) => players.add(p.name)));
        setStats({
          players: players.size,
          games: (hist.data || []).length,
          categories: (cats.data || []).length,
          questions: "50+",
        });
      } catch (err) {
        console.error("API error", err);
      }
    })();
  }, []);

  return (
    <div className="app" data-testid="app-root">
      <Header />
      <main>
        <Hero stats={stats} />
        <About />
        <Modes />
        <Leaderboard rows={leaders} />
        <History rows={history} />
        <BuildInstructions />
      </main>
      <footer className="footer" data-testid="footer">
        SpinnShot · Hecho con Kotlin + Jetpack Compose · Backend FastAPI + MongoDB
      </footer>
    </div>
  );
}
